module RefModule (
    input clk,
    input rst,
    input din,
    output reg [1:0] dout
);
    reg [1:0] counter;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst) begin
            dout <= 2'b00;
            counter <= 2'b00;
        end else begin
            if (counter == 2'b01) begin
                dout <= {din, din}; // Convert 1-bit to 2-bit
                counter <= 2'b00;
            end else begin
                dout <= dout; // Hold the value
                counter <= counter + 1;
            end
        end
    end
endmodule
